-- Fases cadastradas para o Gaúcho
SELECT tp.id, tp.key AS phaseKey, tp.label, tp.enabled, tp.isKnockout, tp.order
FROM tournament_phases tp WHERE tp.tournamentId = 60001 ORDER BY tp.order;

